const htmlFragment = $json.output;

if (!htmlFragment) {
  throw new Error("No HTML content found in 'output'.");
}

// Extract the first <h1> content using RegExp
const match = htmlFragment.match(/<h1>(.*?)<\/h1>/i);
let title = match ? match[1] : 'Untitled';

// Clean the title for use as a filename
title = title.replace(/[^a-z0-9_\- ]/gi, '').trim();
const fileName = `${title || 'Untitled'}.html`;

// Wrap HTML content in full page template
const fullHTML = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>${title}</title>
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body {
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      line-height: 1.6;
      margin: 40px;
      background-color: #fdfdfd;
      color: #333;
    }
    h1, h2, h3 {
      color: #1a237e;
    }
    hr {
      margin: 40px 0;
      border: none;
      border-top: 2px solid #ccc;
    }
    ul {
      margin-left: 20px;
    }
    strong {
      color: #d32f2f;
    }
    em {
      color: #1976d2;
    }
  </style>
</head>
<body>
${htmlFragment}
</body>
</html>
`;

// Convert to binary
const data = await this.helpers.prepareBinaryData(
  Buffer.from(fullHTML, 'utf-8'),
  fileName,
  'text/html'
);

return [
  {
    binary: {
      data
    },
    json: {
      filename: fileName
    }
  }
];

